SELECT
FROM team_recruitment_info WHERE deleted = 0
AND ( event_name LIKE CONCAT('%', #{keyword}, '%') OR direction LIKE CONCAT('%', #{keyword}, '%') OR skill_requirement LIKE CONCAT('%', #{keyword}, '%') )
AND direction = #{direction}
AND recruitment_status = #{recruitmentStatus}
ORDER BY CASE recruitment_status WHEN 'RECRUITING' THEN 1 WHEN 'FULL' THEN 2 WHEN 'CLOSED' THEN 3 WHEN 'EXPIRED' THEN 4 ELSE 99 END ASC, deadline ASC, create_time DESC LIMIT #{offset}, #{limit}

SELECT COUNT(1)
FROM team_recruitment_info
WHERE deleted = 0

    AND (
        event_name LIKE CONCAT('%', #{keyword}, '%')
        OR direction LIKE CONCAT('%', #{keyword}, '%')
        OR skill_requirement LIKE CONCAT('%', #{keyword}, '%')
    )


    AND direction = #{direction}


    AND recruitment_status = #{recruitmentStatus}
